package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    private final UserSessionService userSessionService;
    private final IdTokenClaimsParser idTokenClaimsParser;

    public CustomOidcUserService(UserSessionService userSessionService,
                                  IdTokenClaimsParser idTokenClaimsParser) {
        this.userSessionService = userSessionService;
        this.idTokenClaimsParser = idTokenClaimsParser;
    }

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        try {
            OidcIdToken idToken = userRequest.getIdToken();

            // Parse and validate id_token claims
            UserSession userSession = idTokenClaimsParser.parseIdTokenClaims(idToken);
            userSession.setAccessToken(userRequest.getAccessToken().getTokenValue());
            userSession.setIdToken(idToken.getTokenValue());

            // Extract roles/authorities from claims
            Set<GrantedAuthority> authorities = extractAuthorities(idToken);

            // Merge with existing authorities
            Set<GrantedAuthority> allAuthorities = new HashSet<>(oidcUser.getAuthorities());
            allAuthorities.addAll(authorities);

            // Store session
            userSessionService.createSession(userSession);

            logger.info("Successfully authenticated user: {} (sub: {})",
                    userSession.getEmail(), userSession.getSubject());

            return new DefaultOidcUser(
                    allAuthorities,
                    oidcUser.getIdToken(),
                    oidcUser.getUserInfo(),
                    "sub"
            );

        } catch (Exception e) {
            logger.error("Error processing OIDC user", e);
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("user_processing_error"),
                    "Error processing authenticated user: " + e.getMessage(), e);
        }
    }

    private Set<GrantedAuthority> extractAuthorities(OidcIdToken idToken) {
        Set<GrantedAuthority> authorities = new HashSet<>();

        // Extract roles from 'roles' claim
        Object rolesClaim = idToken.getClaim("roles");
        if (rolesClaim instanceof Collection) {
            ((Collection<?>) rolesClaim).stream()
                    .map(Object::toString)
                    .map(role -> role.startsWith("ROLE_") ? role : "ROLE_" + role.toUpperCase())
                    .map(SimpleGrantedAuthority::new)
                    .forEach(authorities::add);
        }

        // Extract roles from 'groups' claim
        Object groupsClaim = idToken.getClaim("groups");
        if (groupsClaim instanceof Collection) {
            ((Collection<?>) groupsClaim).stream()
                    .map(Object::toString)
                    .map(group -> "ROLE_" + group.toUpperCase().replace(" ", "_"))
                    .map(SimpleGrantedAuthority::new)
                    .forEach(authorities::add);
        }

        // Extract from realm_access (Keycloak-style)
        Object realmAccess = idToken.getClaim("realm_access");
        if (realmAccess instanceof Map) {
            Object roles = ((Map<?, ?>) realmAccess).get("roles");
            if (roles instanceof Collection) {
                ((Collection<?>) roles).stream()
                        .map(Object::toString)
                        .map(role -> "ROLE_" + role.toUpperCase())
                        .map(SimpleGrantedAuthority::new)
                        .forEach(authorities::add);
            }
        }

        // Default role if none found
        if (authorities.isEmpty()) {
            authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
        }

        return authorities;
    }
}

// ==================== ID Token Claims Parser ====================

package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.OAuth2Error;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.*;

@Component
public class IdTokenClaimsParser {

    private static final Logger logger = LoggerFactory.getLogger(IdTokenClaimsParser.class);

    public UserSession parseIdTokenClaims(OidcIdToken idToken) {
        validateRequiredClaims(idToken);

        UserSession session = new UserSession();

        // Standard OIDC claims
        session.setSubject(idToken.getSubject());
        session.setIssuer(idToken.getIssuer() != null ? idToken.getIssuer().toString() : null);
        session.setAudience(idToken.getAudience());
        session.setIssuedAt(idToken.getIssuedAt());
        session.setExpiresAt(idToken.getExpiresAt());
        session.setNonce(idToken.getNonce());
        session.setAuthTime(idToken.getAuthenticatedAt());

        // Profile claims
        session.setFullName(idToken.getFullName());
        session.setGivenName(idToken.getGivenName());
        session.setFamilyName(idToken.getFamilyName());
        session.setPreferredUsername(idToken.getPreferredUsername());
        session.setEmail(idToken.getEmail());
        session.setEmailVerified(idToken.getEmailVerified());
        session.setPicture(idToken.getPicture());
        session.setLocale(idToken.getLocale());
        session.setZoneInfo(idToken.getZoneInfo());

        // Extract roles
        List<String> roles = extractRoles(idToken);
        session.setRoles(roles);

        // Store all claims for future reference
        session.setAllClaims(new HashMap<>(idToken.getClaims()));

        // Session metadata
        session.setSessionId(UUID.randomUUID().toString());
        session.setCreatedAt(Instant.now());

        logger.debug("Parsed ID token claims for subject: {}, email: {}, roles: {}",
                session.getSubject(), session.getEmail(), session.getRoles());

        return session;
    }

    private void validateRequiredClaims(OidcIdToken idToken) {
        if (idToken.getSubject() == null || idToken.getSubject().isBlank()) {
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("invalid_id_token"),
                    "ID token missing required 'sub' claim");
        }

        if (idToken.getIssuer() == null) {
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("invalid_id_token"),
                    "ID token missing required 'iss' claim");
        }

        if (idToken.getExpiresAt() == null) {
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("invalid_id_token"),
                    "ID token missing required 'exp' claim");
        }

        if (idToken.getExpiresAt().isBefore(Instant.now())) {
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("invalid_id_token"),
                    "ID token has expired");
        }

        if (idToken.getIssuedAt() != null && idToken.getIssuedAt().isAfter(Instant.now())) {
            throw new OAuth2AuthenticationException(
                    new OAuth2Error("invalid_id_token"),
                    "ID token issued in the future");
        }
    }

    @SuppressWarnings("unchecked")
    private List<String> extractRoles(OidcIdToken idToken) {
        List<String> roles = new ArrayList<>();

        // Try 'roles' claim
        Object rolesClaim = idToken.getClaim("roles");
        if (rolesClaim instanceof Collection) {
            ((Collection<?>) rolesClaim).forEach(r -> roles.add(r.toString()));
        }

        // Try 'groups' claim
        Object groupsClaim = idToken.getClaim("groups");
        if (groupsClaim instanceof Collection) {
            ((Collection<?>) groupsClaim).forEach(g -> roles.add(g.toString()));
        }

        // Try Keycloak realm_access
        Object realmAccess = idToken.getClaim("realm_access");
        if (realmAccess instanceof Map) {
            Object realmRoles = ((Map<String, Object>) realmAccess).get("roles");
            if (realmRoles instanceof Collection) {
                ((Collection<?>) realmRoles).forEach(r -> roles.add(r.toString()));
            }
        }

        return roles;
    }
}

