// ==================== User Session Service ====================

package com.example.oidcclient.service;

import com.example.oidcclient.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);

    // In production, use Redis or a database-backed session store
    private final Map<String, UserSession> sessionStore = new ConcurrentHashMap<>();
    private final Map<String, String> subjectToSessionMap = new ConcurrentHashMap<>();

    public void createSession(UserSession userSession) {
        // Remove any existing session for this subject
        String existingSessionId = subjectToSessionMap.get(userSession.getSubject());
        if (existingSessionId != null) {
            sessionStore.remove(existingSessionId);
            logger.debug("Removed existing session for subject: {}", userSession.getSubject());
        }

        userSession.setCreatedAt(Instant.now());
        userSession.setLastAccessedAt(Instant.now());

        sessionStore.put(userSession.getSessionId(), userSession);
        subjectToSessionMap.put(userSession.getSubject(), userSession.getSessionId());

        logger.info("Created session {} for user {} (sub: {})",
                userSession.getSessionId(), userSession.getEmail(), userSession.getSubject());
    }

    public Optional<UserSession> getSession(String sessionId) {
        UserSession session = sessionStore.get(sessionId);
        if (session != null) {
            if (session.isExpired()) {
                removeSession(sessionId);
                return Optional.empty();
            }
            session.setLastAccessedAt(Instant.now());
        }
        return Optional.ofNullable(session);
    }

    public Optional<UserSession> getSessionBySubject(String subject) {
        String sessionId = subjectToSessionMap.get(subject);
        if (sessionId != null) {
            return getSession(sessionId);
        }
        return Optional.empty();
    }

    public void removeSession(String sessionId) {
        UserSession session = sessionStore.remove(sessionId);
        if (session != null) {
            subjectToSessionMap.remove(session.getSubject());
            logger.info("Removed session {} for subject: {}", sessionId, session.getSubject());
        }
    }

    public void removeSessionBySubject(String subject) {
        String sessionId = subjectToSessionMap.get(subject);
        if (sessionId != null) {
            removeSession(sessionId);
        }
    }

    public int getActiveSessionCount() {
        return sessionStore.size();
    }
}

// ==================== Token Exchange Service ====================

package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProviderProperties;
import com.example.oidcclient.model.TokenResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.util.Base64;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final OidcProviderProperties oidcProperties;
    private final RestTemplate restTemplate;

    public TokenExchangeService(OidcProviderProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
        this.restTemplate = new RestTemplate();
    }

    public TokenResponse exchangeAuthorizationCode(String authorizationCode, String redirectUri) {
        logger.debug("Exchanging authorization code for tokens at: {}", oidcProperties.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        // Basic auth with client credentials
        String credentials = oidcProperties.getClientId() + ":" + oidcProperties.getClientSecret();
        String encodedCredentials = Base64.getEncoder().encodeToString(credentials.getBytes());
        headers.set("Authorization", "Basic " + encodedCredentials);

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "authorization_code");
        params.add("code", authorizationCode);
        params.add("redirect_uri", redirectUri != null ? redirectUri : oidcProperties.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        try {
            ResponseEntity<TokenResponse> response = restTemplate.exchange(
                    oidcProperties.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    TokenResponse.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully exchanged authorization code for tokens");
                return response.getBody();
            } else {
                throw new RuntimeException("Token exchange failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Failed to exchange authorization code", e);
            throw new RuntimeException("Token exchange failed: " + e.getMessage(), e);
        }
    }

    public TokenResponse refreshAccessToken(String refreshToken) {
        logger.debug("Refreshing access token at: {}", oidcProperties.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        String credentials = oidcProperties.getClientId() + ":" + oidcProperties.getClientSecret();
        String encodedCredentials = Base64.getEncoder().encodeToString(credentials.getBytes());
        headers.set("Authorization", "Basic " + encodedCredentials);

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "refresh_token");
        params.add("refresh_token", refreshToken);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        try {
            ResponseEntity<TokenResponse> response = restTemplate.exchange(
                    oidcProperties.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    TokenResponse.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully refreshed access token");
                return response.getBody();
            } else {
                throw new RuntimeException("Token refresh failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Failed to refresh access token", e);
            throw new RuntimeException("Token refresh failed: " + e.getMessage(), e);
        }
    }

    public Map<String, Object> getUserInfo(String accessToken) {
        logger.debug("Fetching user info from: {}", oidcProperties.getUserInfoUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);

        HttpEntity<Void> request = new HttpEntity<>(headers);

        try {
            @SuppressWarnings("unchecked")
            ResponseEntity<java.util.Map> response = restTemplate.exchange(
                    oidcProperties.getUserInfoUri(),
                    HttpMethod.GET,
                    request,
                    java.util.Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully fetched user info");
                return response.getBody();
            } else {
                throw new RuntimeException("UserInfo request failed with status: " + response.getStatusCode());
            }
        } catch (Exception e) {
            logger.error("Failed to fetch user info", e);
            throw new RuntimeException("UserInfo request failed: " + e.getMessage(), e);
        }
    }
}

