package com.example.oidcclient.model;

import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
import com.fasterxml.jackson.annotation.JsonProperty;

@JsonIgnoreProperties(ignoreUnknown = true)
public class TokenResponse {

    @JsonProperty("access_token")
    private String accessToken;

    @JsonProperty("token_type")
    private String tokenType;

    @JsonProperty("expires_in")
    private Long expiresIn;

    @JsonProperty("refresh_token")
    private String refreshToken;

    @JsonProperty("id_token")
    private String idToken;

    @JsonProperty("scope")
    private String scope;

    public String getAccessToken() { return accessToken; }
    public void setAccessToken(String accessToken) { this.accessToken = accessToken; }
    public String getTokenType() { return tokenType; }
    public void setTokenType(String tokenType) { this.tokenType = tokenType; }
    public Long getExpiresIn() { return expiresIn; }
    public void setExpiresIn(Long expiresIn) { this.expiresIn = expiresIn; }
    public String getRefreshToken() { return refreshToken; }
    public void setRefreshToken(String refreshToken) { this.refreshToken = refreshToken; }
    public String getIdToken() { return idToken; }
    public void setIdToken(String idToken) { this.idToken = idToken; }
    public String getScope() { return scope; }
    public void setScope(String scope) { this.scope = scope; }
}

// ==================== Custom Authentication Success Handler ====================

package com.example.oidcclient.config;

import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.UserSessionService;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.SavedRequestAwareAuthenticationSuccessHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;
import java.util.Optional;

@Component
public class CustomAuthenticationSuccessHandler extends SavedRequestAwareAuthenticationSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(CustomAuthenticationSuccessHandler.class);

    private final UserSessionService userSessionService;

    public CustomAuthenticationSuccessHandler(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
        setDefaultTargetUrl("/dashboard");
        setAlwaysUseDefaultTargetUrl(false);
    }

    @Override
    public void onAuthenticationSuccess(HttpServletRequest request,
                                         HttpServletResponse response,
                                         Authentication authentication) throws IOException, ServletException {

        if (authentication.getPrincipal() instanceof OidcUser oidcUser) {
            String subject = oidcUser.getSubject();
            Optional<UserSession> session = userSessionService.getSessionBySubject(subject);

            session.ifPresent(s -> {
                request.getSession().setAttribute("USER_SESSION", s);
                request.getSession().setAttribute("USER_EMAIL", s.getEmail());
                request.getSession().setAttribute("USER_NAME", s.getFullName());
                logger.info("User session stored in HTTP session for: {}", s.getEmail());
            });
        }

        super.onAuthenticationSuccess(request, response, authentication);
    }
}

// ==================== Custom Authentication Failure Handler ====================

package com.example.oidcclient.config;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.web.authentication.SimpleUrlAuthenticationFailureHandler;
import org.springframework.stereotype.Component;

import java.io.IOException;

@Component
public class CustomAuthenticationFailureHandler extends SimpleUrlAuthenticationFailureHandler {

    private static final Logger logger = LoggerFactory.getLogger(CustomAuthenticationFailureHandler.class);

    public CustomAuthenticationFailureHandler() {
        setDefaultFailureUrl("/login?error=true");
    }

    @Override
    public void onAuthenticationFailure(HttpServletRequest request,
                                         HttpServletResponse response,
                                         AuthenticationException exception) throws IOException, ServletException {
        logger.error("Authentication failed: {}", exception.getMessage());
        request.getSession().setAttribute("AUTH_ERROR", exception.getMessage());
        super.onAuthenticationFailure(request, response, exception);
    }
}

// ==================== Custom OIDC Logout Success Handler ====================

package com.example.oidcclient.config;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.security.web.authentication.logout.LogoutSuccessHandler;
import org.springframework.web.util.UriComponentsBuilder;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;

public class CustomOidcLogoutSuccessHandler implements LogoutSuccessHandler {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcLogoutSuccessHandler.class);

    private final OidcProviderProperties oidcProperties;

    public CustomOidcLogoutSuccessHandler(OidcProviderProperties oidcProperties) {
        this.oidcProperties = oidcProperties;
    }

    @Override
    public void onLogoutSuccess(HttpServletRequest request,
                                 HttpServletResponse response,
                                 Authentication authentication) throws IOException, ServletException {

        String redirectUrl;

        if (authentication != null && authentication.getPrincipal() instanceof OidcUser oidcUser
                && oidcProperties.getEndSessionUri() != null) {

            String idToken = oidcUser.getIdToken().getTokenValue();

            redirectUrl = UriComponentsBuilder.fromUriString(oidcProperties.getEndSessionUri())
                    .queryParam("id_token_hint", idToken)
                    .queryParam("post_logout_redirect_uri",
                            oidcProperties.getPostLogoutRedirectUri() != null
                                    ? oidcProperties.getPostLogoutRedirectUri()
                                    : request.getScheme() + "://" + request.getServerName()
                                    + ":" + request.getServerPort() + "/")
                    .build()
                    .toUriString();

            logger.info("Redirecting to OIDC provider end session endpoint");
        } else {
            redirectUrl = "/login?logout";
            logger.info("Redirecting to local login page after logout");
        }

        response.sendRedirect(redirectUrl);
    }
}

// ==================== Web Controllers ====================

package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.UserSessionService;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.util.Optional;

@Controller
public class HomeController {

    private final UserSessionService userSessionService;

    public HomeController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/")
    public String home() {
        return "home";
    }

    @GetMapping("/login")
    public String login() {
        return "login";
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("userName", oidcUser.getFullName());
            model.addAttribute("email", oidcUser.getEmail());
            model.addAttribute("subject", oidcUser.getSubject());
            model.addAttribute("claims", oidcUser.getClaims());
            model.addAttribute("authorities", oidcUser.getAuthorities());

            Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
            session.ifPresent(s -> model.addAttribute("userSession", s));
        }
        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("user", oidcUser);
            model.addAttribute("idTokenClaims", oidcUser.getIdToken().getClaims());
            model.addAttribute("userInfoClaims", oidcUser.getUserInfo() != null
                    ? oidcUser.getUserInfo().getClaims() : null);
        }
        return "profile";
    }
}

// ==================== REST API Controller ====================

package com.example.oidcclient.controller;

import com.example.oidcclient.model.UserSession;
import com.example.oidcclient.service.TokenExchangeService;
import com.example.oidcclient.service.UserSessionService;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api")
public class ApiController {

    private final UserSessionService userSessionService;
    private final TokenExchangeService tokenExchangeService;

    public ApiController(UserSessionService userSessionService,
                         TokenExchangeService tokenExchangeService) {
        this.userSessionService = userSessionService;
        this.tokenExchangeService = tokenExchangeService;
    }

    @GetMapping("/me")
    public ResponseEntity<Map<String, Object>> getCurrentUser(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("subject", oidcUser.getSubject());
        userInfo.put("name", oidcUser.getFullName());
        userInfo.put("email", oidcUser.getEmail());
        userInfo.put("emailVerified", oidcUser.getEmailVerified());
        userInfo.put("authorities", oidcUser.getAuthorities());

        Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
        session.ifPresent(s -> {
            userInfo.put("sessionId", s.getSessionId());
            userInfo.put("roles", s.getRoles());
            userInfo.put("sessionCreatedAt", s.getCreatedAt());
            userInfo.put("tokenExpiresAt", s.getExpiresAt());
        });

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/session/info")
    public ResponseEntity<Map<String, Object>> getSessionInfo(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> sessionInfo = new HashMap<>();
        sessionInfo.put("activeSessions", userSessionService.getActiveSessionCount());

        Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
        session.ifPresent(s -> {
            sessionInfo.put("sessionId", s.getSessionId());
            sessionInfo.put("createdAt", s.getCreatedAt());
            sessionInfo.put("lastAccessedAt", s.getLastAccessedAt());
            sessionInfo.put("expiresAt", s.getExpiresAt());
            sessionInfo.put("isExpired", s.isExpired());
        });

        return ResponseEntity.ok(sessionInfo);
    }

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> getUserInfoFromProvider(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Optional<UserSession> session = userSessionService.getSessionBySubject(oidcUser.getSubject());
        if (session.isPresent() && session.get().getAccessToken() != null) {
            Map<String, Object> userInfo = tokenExchangeService.getUserInfo(session.get().getAccessToken());
            return ResponseEntity.ok(userInfo);
        }

        return ResponseEntity.status(400).body(Map.of("error", "No access token available"));
    }

    @GetMapping("/claims")
    public ResponseEntity<Map<String, Object>> getIdTokenClaims(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        return ResponseEntity.ok(oidcUser.getIdToken().getClaims());
    }
}

